INSERT INTO `v1_390f536631661939de9702e77e2368340219a7eaa34bc68c26c2247bdca8f70c` VALUES (0, "2025/12/31 11:59:59", 0, 0, 0, 0, 119901, 0, "みやこ", 0, 1, 14, 1, 3, "【物理】中衛で、味方をプリンで強化する幽霊聖少女。\n物理攻撃力と物理クリティカルアップのプリンパワーの\nフィールドで自分のスキルも強化し、猛攻を繰り出す。", 302, 2.17, 119901, 119901, "2025/12/21 12:00:00", 119901, 1, 1, "ミヤコ（クリスマス）", 450);
INSERT INTO `v1_390f536631661939de9702e77e2368340219a7eaa34bc68c26c2247bdca8f70c` VALUES (0, "2026/03/31 11:59:59", 0, 0, 0, 0, 120001, 0, "しずる", 0, 1, 6, 5, 3, "【物理】前衛で猛攻から味方を守護する闇のお姉ちゃん。\nバトル開始時の行動不能無効スキルで周囲の味方を守り、\n範囲を束縛するスキルで敵を牽制し、戦況を一変する。", 190, 2.375, 120001, 120001, "2026/03/16 10:00:00", 120001, 1, 5, "シズル（ノワール）", 450);
INSERT INTO `v1_390f536631661939de9702e77e2368340219a7eaa34bc68c26c2247bdca8f70c` VALUES (0, "2030/12/31 15:00:00", 0, 0, 0, 0, 120101, 0, "いお", 0, 0, 0, 7, 3, "", 0, 0.0, 120101, 0, "2015/04/01 15:00:00", 0, 0, 7, "イオ（ノワール）", 0);
